import React, { useState } from 'react';
import axios from 'axios';
import styles from '../Styles/Pages/Dashboard.module.css';
import Header from '../Components/Header';
import CardRelatorio from '../Components/CardRelatorio';
import EvolucaoTurno from '../Components/EvolucaoTurno'; 
import ObservacoesTurno from '../Components/ObservacoesTurno';
import Arquivo from "../Assets/Icons/Arquivo.svg";

const getTurnoAtual = () => {
  const agora = new Date();
  const tempoEmMinutos = agora.getHours() * 60 + agora.getMinutes();
  const limiteT1 = 6 * 60;          // 06:00
  const limiteT2 = 14 * 60 + 25;    // 14:25
  const limiteT3 = 22 * 60 + 50;    // 22:50

  if (tempoEmMinutos >= limiteT1 && tempoEmMinutos < limiteT2) return { atual: "T1", proximo: "T2" };
  if (tempoEmMinutos >= limiteT2 && tempoEmMinutos < limiteT3) return { atual: "T2", proximo: "T3" };
  return { atual: "T3", proximo: "T1" };
};

const Dashboard = () => {
  const infoTurno = getTurnoAtual();
  const dataHoje = new Date().toLocaleDateString('pt-BR');

  // 1. Estados para os dados (Iniciam como null ou objeto vazio)
  const [dadosIniciais, setDadosIniciais] = useState(null);
  const [dadosFinais, setDadosFinais] = useState(null);
  const [carregando, setCarregando] = useState(false);

  // 2. Função para lidar com o upload do arquivo
  const handleFileUpload = async (event) => {
    const file = event.target.files[0];
    if (!file) return;

    setCarregando(true);
    const formData = new FormData();
    formData.append('report', file); // 'report' deve ser o nome usado no multer do backend

    try {
      // Ajuste o endpoint para a URL do seu servidor Node.js
      const response = await axios.post('http://localhost:3001/api/reports/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      // 3. Supondo que o backend retorne { inicial: {...}, final: {...} }
      setDadosIniciais(response.data.inicial);
      setDadosFinais(response.data.final);
    } catch (error) {
      console.error("Erro ao processar planilha:", error);
      alert("Erro ao ler o arquivo do BI. Verifique o formato.");
    } finally {
      setCarregando(false);
    }
  };

  return (
    <div className={styles.container}>
      <Header
        turnoAtual={infoTurno.atual}
        proximoTurno={infoTurno.proximo}
        data={dataHoje}
      />

      <section className={styles.pageTitleSection}>
        <h1 className={styles.pageTitle}>Relatório - Tratativas Solver</h1>

        <label htmlFor="file-upload" className={styles.uploadBox}>
          <img src={Arquivo} alt="" className={styles.uploadIcon} />
          <span className={styles.uploadText}>
            {carregando ? "Processando..." : "Anexe o arquivo retirado do BI"}
          </span>
          <input 
            type="file" 
            id="file-upload" 
            className={styles.hiddenInput} 
            onChange={handleFileUpload}
            accept=".xlsx, .xls"
          />
        </label>
      </section>

      <main className={styles.mainContent}>
  <section className={styles.cardsSection}>
    {/* Remova o "dadosIniciais &&" de antes do componente */}
    <CardRelatorio
      titulo="Cenário Inicial"
      // Usa um valor padrão caso o estado esteja vazio
      total={dadosIniciais ? dadosIniciais.backlog.toLocaleString('pt-BR') : "0"}
      cor="#B91C1C"
      itens={dadosIniciais ? dadosIniciais.lista : []}
      totalPecas={dadosIniciais ? dadosIniciais.pecasFalta.toLocaleString('pt-BR') : "0"}
    />

    <CardRelatorio
      titulo="Cenário Final"
      total={dadosFinais ? dadosFinais.backlog.toLocaleString('pt-BR') : "0"}
      cor="#007A5E"
      itens={dadosFinais ? dadosFinais.lista : []}
      totalPecas={dadosFinais ? dadosFinais.pecasFalta.toLocaleString('pt-BR') : "0"}
    />
  </section>

  {/* A Evolução só faz sentido aparecer se houver dados para comparar */}
  {dadosIniciais && dadosFinais && (
    <EvolucaoTurno
      dadosIniciais={dadosIniciais}
      dadosFinais={dadosFinais}
      cor="#B91C1C"
    />
  )}

  <ObservacoesTurno />
</main>
    </div>
  );
};

export default Dashboard;
